import{_ as t,o as r,c as s,ai as i}from"./chunks/framework.Bke2s2V8.js";const p=JSON.parse(`{"title":"L'ordre des mots","description":"","frontmatter":{"prev":{"text":"Introduction Module 2","link":"/module-2-construire-une-phrase/"}},"headers":[],"relativePath":"module-2-construire-une-phrase/ordre-des-mots.md","filePath":"module-2-construire-une-phrase/ordre-des-mots.md","lastUpdated":1773298982000}`),a={name:"module-2-construire-une-phrase/ordre-des-mots.md"};function o(d,e,n,l,u,c){return r(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="l-ordre-des-mots" tabindex="-1">L&#39;ordre des mots <a class="header-anchor" href="#l-ordre-des-mots" aria-label="Permalink to “L&#39;ordre des mots”">​</a></h1><p><strong>Prérequis :</strong> <a href="./index.html">Introduction Module 2</a></p><p><strong>Objectif :</strong> comprendre la règle fondamentale de la phrase allemande - le verbe est toujours en deuxième position.</p><p>C&#39;est la règle la plus importante de la syntaxe allemande. Une fois assimilee, tout le reste devient beaucoup plus logique.</p><h2 id="la-regle-v2" tabindex="-1">La règle V2 <a class="header-anchor" href="#la-regle-v2" aria-label="Permalink to “La règle V2”">​</a></h2><p>En allemand, le verbe conjugue occupe <strong>toujours la deuxième position</strong> dans une phrase declarative. Peu importe ce qui vient en premier - le sujet, un complément de temps, un complément de lieu - le verbe reste en deuxième position.</p><div class="info custom-block"><p class="custom-block-title">Ce qu&#39;on appelle &quot;position&quot;</p><p>On ne compte pas les mots, mais les groupes de mots. <em>Aujourd&#39;hui matin</em> est un seul groupe, pas deux positions. C&#39;est la position du groupe qui compte.</p></div><h3 id="structure-de-base-sujet-verbe-complement" tabindex="-1">Structure de base : Sujet - Verbe - Complement <a class="header-anchor" href="#structure-de-base-sujet-verbe-complement" aria-label="Permalink to “Structure de base : Sujet - Verbe - Complement”">​</a></h3><div class="mt-4 grid gap-3"><div class="p-4 rounded-lg border border-gray-200"><div class="grid grid-cols-3 gap-2 text-center mb-3"><div class="bg-blue-50 border border-blue-200 rounded p-2"><div class="text-xs text-blue-500 font-medium">Position 1</div><div class="font-bold text-blue-800">Ich</div></div><div class="bg-green-50 border border-green-200 rounded p-2"><div class="text-xs text-green-500 font-medium">Position 2 - Verbe</div><div class="font-bold text-green-800">lerne</div></div><div class="bg-gray-50 border border-gray-200 rounded p-2"><div class="text-xs text-gray-500 font-medium">Reste</div><div class="font-bold text-gray-700">Deutsch.</div></div></div><div class="text-sm text-gray-500 text-center">J&#39;apprends l&#39;allemand.</div></div><div class="p-4 rounded-lg border border-gray-200"><div class="grid grid-cols-3 gap-2 text-center mb-3"><div class="bg-blue-50 border border-blue-200 rounded p-2"><div class="text-xs text-blue-500 font-medium">Position 1</div><div class="font-bold text-blue-800">Er</div></div><div class="bg-green-50 border border-green-200 rounded p-2"><div class="text-xs text-green-500 font-medium">Position 2 - Verbe</div><div class="font-bold text-green-800">wohnt</div></div><div class="bg-gray-50 border border-gray-200 rounded p-2"><div class="text-xs text-gray-500 font-medium">Reste</div><div class="font-bold text-gray-700">in Berlin.</div></div></div><div class="text-sm text-gray-500 text-center">Il habite a Berlin.</div></div></div><h3 id="l-inversion-quand-autre-chose-est-en-position-1" tabindex="-1">L&#39;inversion : quand autre chose est en position 1 <a class="header-anchor" href="#l-inversion-quand-autre-chose-est-en-position-1" aria-label="Permalink to “L&#39;inversion : quand autre chose est en position 1”">​</a></h3><p>Si on place un élément autre que le sujet en première position (pour insister ou varier), le verbe reste en deuxième position et le sujet passe après le verbe.</p><div class="mt-4 grid gap-3"><div class="p-4 rounded-lg border border-gray-200"><div class="grid grid-cols-4 gap-2 text-center mb-3"><div class="bg-orange-50 border border-orange-200 rounded p-2"><div class="text-xs text-orange-500 font-medium">Position 1</div><div class="font-bold text-orange-800">Heute</div></div><div class="bg-green-50 border border-green-200 rounded p-2"><div class="text-xs text-green-500 font-medium">Position 2 - Verbe</div><div class="font-bold text-green-800">lerne</div></div><div class="bg-blue-50 border border-blue-200 rounded p-2"><div class="text-xs text-blue-500 font-medium">Sujet après</div><div class="font-bold text-blue-800">ich</div></div><div class="bg-gray-50 border border-gray-200 rounded p-2"><div class="text-xs text-gray-500 font-medium">Reste</div><div class="font-bold text-gray-700">Deutsch.</div></div></div><div class="text-sm text-gray-500 text-center">Aujourd&#39;hui, j&#39;apprends l&#39;allemand. (accent mis sur &quot;aujourd&#39;hui&quot;)</div></div><div class="p-4 rounded-lg border border-gray-200"><div class="grid grid-cols-4 gap-2 text-center mb-3"><div class="bg-orange-50 border border-orange-200 rounded p-2"><div class="text-xs text-orange-500 font-medium">Position 1</div><div class="font-bold text-orange-800">In Berlin</div></div><div class="bg-green-50 border border-green-200 rounded p-2"><div class="text-xs text-green-500 font-medium">Position 2 - Verbe</div><div class="font-bold text-green-800">wohnt</div></div><div class="bg-blue-50 border border-blue-200 rounded p-2"><div class="text-xs text-blue-500 font-medium">Sujet après</div><div class="font-bold text-blue-800">er</div></div><div class="bg-gray-50 border border-gray-200 rounded p-2"><div class="text-xs text-gray-500 font-medium">Reste</div><div class="font-bold text-gray-700">seit Jahren.</div></div></div><div class="text-sm text-gray-500 text-center">A Berlin, il habite depuis des annees.</div></div></div><div class="warning custom-block"><p class="custom-block-title">L&#39;inversion n&#39;existe pas en français de la même façon</p><p>En français, on peut dire &quot;Aujourd&#39;hui, j&#39;apprends l&#39;allemand&quot; sans changer l&#39;ordre sujet-verbe. En allemand, mettre un autre élément en position 1 force obligatoirement l&#39;inversion : <em>Heute lerne ich...</em> et non <em>Heute ich lerne</em>.</p></div><h2 id="les-questions" tabindex="-1">Les questions <a class="header-anchor" href="#les-questions" aria-label="Permalink to “Les questions”">​</a></h2><h3 id="question-avec-mot-interrogatif-w-frage" tabindex="-1">Question avec mot interrogatif (W-Frage) <a class="header-anchor" href="#question-avec-mot-interrogatif-w-frage" aria-label="Permalink to “Question avec mot interrogatif (W-Frage)”">​</a></h3><p>Le mot interrogatif occupe la position 1, le verbe reste en position 2 :</p><ul><li><em>Wo wohnst du ?</em> - Ou habites-tu ?</li><li><em>Was machst du ?</em> - Qu&#39;est-ce que tu fais ?</li><li><em>Wann kommst du ?</em> - Quand viens-tu ?</li></ul><h3 id="question-fermee-oui-non" tabindex="-1">Question fermee (oui/non) <a class="header-anchor" href="#question-fermee-oui-non" aria-label="Permalink to “Question fermee (oui/non)”">​</a></h3><p>Dans une question sans mot interrogatif, le verbe passe en première position :</p><ul><li><em>Wohnst du in Berlin ?</em> - Tu habites a Berlin ?</li><li><em>Lernst du Deutsch ?</em> - Tu apprends l&#39;allemand ?</li></ul><div class="tip custom-block"><p class="custom-block-title">Position 0 : und, aber, oder, denn</p><p>Les conjonctions de coordination <em>und</em> (et), <em>aber</em> (mais), <em>oder</em> (ou), <em>denn</em> (car) ne comptent pas comme une position — elles sont en « position 0 ». Le verbe reste en deuxième position dans la phrase qui suit.</p><p><em>Ich lerne Deutsch <strong>und</strong> ich spreche ein bisschen.</em> - J&#39;apprends l&#39;allemand et je parlé un peu.</p></div><h2 id="ce-que-ca-change-par-rapport-au-francais" tabindex="-1">Ce que ca change par rapport au français <a class="header-anchor" href="#ce-que-ca-change-par-rapport-au-francais" aria-label="Permalink to “Ce que ca change par rapport au français”">​</a></h2><p>En allemand, la flexibilité dans l&#39;ordre des mots n&#39;altère pas le sens - les cas grammaticaux (nominatif, accusatif...) jouent ce role. L&#39;ordre sert à mettre en valeur un élément. C&#39;est une logique différente du français, mais très cohérente une fois qu&#39;on l&#39;a intégrée.</p>',23)])])}const v=t(a,[["render",o]]);export{p as __pageData,v as default};
